import{_ as r,o as t,c as n,a as o}from"./chunks/framework.8tiMeCK-.js";const h=JSON.parse('{"title":"9.12  进阶阅读与技术地图","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch09_12.md","filePath":"notes/linux_kernel_debugging/ch09_12.md","lastUpdated":null}'),l={name:"notes/linux_kernel_debugging/ch09_12.md"};function a(i,e,s,c,g,p){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_9-12-进阶阅读与技术地图" tabindex="-1">9.12 进阶阅读与技术地图 <a class="header-anchor" href="#_9-12-进阶阅读与技术地图" aria-label="Permalink to &quot;9.12  进阶阅读与技术地图&quot;">​</a></h1><p>本章的内容到此结束，但你的探索才刚刚开始。</p><p>在这一节里，我整理了一份「进阶阅读地图」。这不仅仅是把书里的链接罗列出来，而是要把它们放在你的认知地图里——告诉你哪些资源是地图，哪些是矿藏，哪些是当你遇到特定怪兽时需要拔出的专用武器。</p><p>把这些资源当作你随身工具箱的扩展说明。</p><hr><h3 id="🗺️-宏观视野-理解-tracing-的全景" tabindex="-1">🗺️ 宏观视野：理解 Tracing 的全景 <a class="header-anchor" href="#🗺️-宏观视野-理解-tracing-的全景" aria-label="Permalink to &quot;🗺️ 宏观视野：理解 Tracing 的全景&quot;">​</a></h3><p>在深入具体的命令之前，先从高处看看这片森林。以下几篇文章适合用来建立整体认知，特别是当你搞不清楚 <code>ftrace</code>、<code>perf</code>、<code>eBPF</code> 和 <code>LTTng</code> 之间到底是什么关系时。</p><ul><li><p><strong>Unified Tracing Platform – Bringing tracing together</strong></p><ul><li><em>Steven Rostedt (VMware), 2019</em></li><li><a href="https://static.sched.com/hosted_files/osseu19/5f/unified-tracing-platform-oss-eu-2019.pdf" target="_blank" rel="noreferrer">https://static.sched.com/hosted_files/osseu19/5f/unified-tracing-platform-oss-eu-2019.pdf</a></li><li><strong>为什么读它</strong>：Ftrace 的主要维护者亲自画蓝图。如果你想了解这些工具未来如何统一到一个架构下，这是第一手资料。</li></ul></li><li><p><strong>Unifying kernel tracing</strong></p><ul><li><em>Jack Edge, LWN, Oct 2019</em></li><li><a href="https://lwn.net/Articles/803347/" target="_blank" rel="noreferrer">https://lwn.net/Articles/803347/</a></li><li><strong>为什么读它</strong>：LWN 的深度一如既往。这篇主要讲如何把 tracefs、perf 和 eBPF 这三座大山连起来。</li></ul></li><li><p><strong>Linux tracing systems &amp; how they fit together</strong></p><ul><li><em>Julia Evans (@b0rk), July 2017</em></li><li><a href="https://jvns.ca/blog/2017/07/05/linux-tracing-systems/" target="_blank" rel="noreferrer">https://jvns.ca/blog/2017/07/05/linux-tracing-systems/</a></li><li><strong>为什么读它</strong>：Julia 的图解能力是一流的。如果你觉得文字描述太抽象，看看她怎么用图表把 Ftrace、Uprobes、SystemTap 等拼在一起。</li></ul></li><li><p><strong>Using the Linux Tracing Infrastructure</strong></p><ul><li><em>Jan Altenberg (Linutronix GmbH), Nov 2017</em></li><li><a href="https://events.static.linuxfound.org/sites/events/files/slides/praesentation_0.pdf" target="_blank" rel="noreferrer">https://events.static.linuxfound.org/sites/events/files/slides/praesentation_0.pdf</a></li><li><strong>为什么读它</strong>：实战导向的幻灯片，包含了不少实际操作中的截图和参数组合。</li></ul></li><li><p><strong>The comprehensive kernel index – all articles on tracing on LWN</strong></p><ul><li><a href="https://lwn.net/Kernel/Index/#Tracing" target="_blank" rel="noreferrer">https://lwn.net/Kernel/Index/#Tracing</a></li><li><strong>为什么收藏它</strong>：LWN 是内核开发者的新闻圣经。这个索引页是所有 Tracing 相关文章的总入口。</li></ul></li></ul><hr><h3 id="⚙️-ftrace-深入内核的开关" tabindex="-1">⚙️ Ftrace：深入内核的开关 <a class="header-anchor" href="#⚙️-ftrace-深入内核的开关" aria-label="Permalink to &quot;⚙️ Ftrace：深入内核的开关&quot;">​</a></h3><p>如果你想挖掘 Ftrace 的潜力，或者只是想确认 <code>set_ftrace_pid</code> 到底怎么用，以下是核心资料。</p><p><strong>官方文档与必读经典</strong></p><ul><li><p><strong>Official kernel documentation – ftrace</strong></p><ul><li><a href="https://www.kernel.org/doc/html/v5.10/trace/ftrace.html" target="_blank" rel="noreferrer">https://www.kernel.org/doc/html/v5.10/trace/ftrace.html</a></li><li><strong>定位</strong>：案头手册。详细到你可能不想一次性读完，但遇到问题时必须查。</li></ul></li><li><p><strong>Ftrace: The hidden light switch</strong></p><ul><li><em>Brendan Gregg, Aug 2014</em></li><li><a href="https://lwn.net/Articles/608497/" target="_blank" rel="noreferrer">https://lwn.net/Articles/608497/</a></li><li><strong>定位</strong>：概念引入。如果你对「为什么 Ftrace 开销这么小」感兴趣，这篇必看。</li></ul></li><li><p><strong>Ftrace internals</strong></p><ul><li><em>Brendan Gregg, Oct 2019</em></li><li><a href="https://www.brendangregg.com/blog/2019-10-15/kernelrecipes-kernel-ftrace-internals.html" target="_blank" rel="noreferrer">https://www.brendangregg.com/blog/2019-10-15/kernelrecipes-kernel-ftrace-internals.html</a></li><li><strong>定位</strong>：硬核内核机制。讲述了 <code>mcount</code>、蹦床和动态插桩的底层黑魔法。</li></ul></li></ul><p><strong>老而弥坚的系列文章</strong> 虽然年代久远，但 Steven Rostedt（Ftrace 之父）的这三篇文章依然是理解设计逻辑的佳作：</p><ul><li><p><strong>Debugging the kernel using Ftrace - part 1 &amp; 2</strong></p><ul><li><em>LWN, Dec 2009</em></li><li><a href="https://lwn.net/Articles/365835/" target="_blank" rel="noreferrer">Part 1</a> | <a href="https://lwn.net/Articles/366796/" target="_blank" rel="noreferrer">Part 2</a></li></ul></li><li><p><strong>Secrets of the Ftrace function tracer</strong></p><ul><li><em>LWN, Jan 2010</em></li><li><a href="https://lwn.net/Articles/370423/" target="_blank" rel="noreferrer">https://lwn.net/Articles/370423/</a></li></ul></li></ul><p><strong>新手入门与速查表</strong></p><ul><li><p><strong>Welcome to ftrace &amp; the Start of Your Journey...</strong></p><ul><li><em>Steven Rostedt, Nov 2019</em></li><li><a href="https://blogs.vmware.com/opensource/2019/11/12/ftrace-linux-kernel/" target="_blank" rel="noreferrer">https://blogs.vmware.com/opensource/2019/11/12/ftrace-linux-kernel/</a></li></ul></li><li><p><strong>ftrace: trace your kernel functions!</strong></p><ul><li><em>Julia Evans, Mar 2017</em></li><li><a href="https://jvns.ca/blog/2017/03/19/getting-started-with-ftrace/" target="_blank" rel="noreferrer">https://jvns.ca/blog/2017/03/19/getting-started-with-ftrace/</a></li><li><strong>定位</strong>：如果你只想看一个教程快速上手，看 Julia 的这篇就够了。</li></ul></li><li><p><strong>Ftrace cheat sheets</strong></p><ul><li>常用命令速查：<a href="http://linux-tipps.blogspot.com/2011/05/ftrace-favorites-cheat-sheet-fun.html" target="_blank" rel="noreferrer">Linux-tipps Cheat Sheet</a></li><li>通用 Kernel Tracing 速查：<a href="https://lzone.de/cheat-sheet/Kernel%20Tracing" target="_blank" rel="noreferrer">lzone.de</a></li><li><strong>建议</strong>：把这几个页面打印出来贴在显示器旁边，直到你把常用的 <code>echo</code> 命令烂熟于心。</li></ul></li></ul><p><strong>内核栈深度专题</strong> 本章我们提到了栈溢出的风险。如果你想深入了解内核栈的机制（特别是 <code>CONFIG_VMAP_STACK</code>），这两篇 LWN 文章是必读的：</p><ul><li><strong>Virtually mapped kernel stacks</strong><ul><li><em>Jon Corbet, June 2016</em></li><li><a href="https://lwn.net/Articles/692208/" target="_blank" rel="noreferrer">https://lwn.net/Articles/692208/</a></li></ul></li><li><strong>Virtually mapped stacks 2: thread_info strikes back</strong><ul><li><em>Jon Corbet, June 2016</em></li><li><a href="https://lwn.net/Articles/692953/" target="_blank" rel="noreferrer">https://lwn.net/Articles/692953/</a></li></ul></li></ul><hr><h3 id="🛠️-工具链-trace-cmd-与-kernelshark" tabindex="-1">🛠️ 工具链：trace-cmd 与 KernelShark <a class="header-anchor" href="#🛠️-工具链-trace-cmd-与-kernelshark" aria-label="Permalink to &quot;🛠️ 工具链：trace-cmd 与 KernelShark&quot;">​</a></h3><p>虽然我们演示了直接操作 <code>tracefs</code>，但在实际工作中，你更需要这些前端工具。</p><p><strong>trace-cmd (命令行前端)</strong></p><ul><li><p><strong>trace-cmd: A front-end for Ftrace</strong></p><ul><li><em>Steven Rostedt, LWN, Oct 2010</em></li><li><a href="https://lwn.net/Articles/410200/" target="_blank" rel="noreferrer">https://lwn.net/Articles/410200/</a></li></ul></li><li><p><strong>Kernel tracing with trace-cmd</strong></p><ul><li><em>G Kamathe (RedHat), July 2021</em></li><li><a href="https://opensource.com/article/21/7/linux-kernel-trace-cmd" target="_blank" rel="noreferrer">https://opensource.com/article/21/7/linux-kernel-trace-cmd</a></li><li><strong>实战价值</strong>：包含具体的 <code>trace-cmd record</code> 和 <code>report</code> 示例。</li></ul></li></ul><p><strong>KernelShark (图形化神器)</strong></p><ul><li><strong>Official KernelShark Documentation</strong><ul><li><a href="https://www.kernelshark.org/Documentation.html" target="_blank" rel="noreferrer">https://www.kernelshark.org/Documentation.html</a></li></ul></li><li><strong>Swimming with the New KernelShark</strong><ul><li><em>Yordan Karadzhov (VMware), 2018</em></li><li><a href="https://events19.linuxfoundation.org/wp-content/uploads/2017/12/Swimming-with-the-New-KernelShark-Yordan-Karadzhov-VMware.pdf" target="_blank" rel="noreferrer">PDF</a></li><li><strong>提示</strong>：KernelShark v2 有了巨大的架构重写（基于 Qt），这篇 PPT 能带你快速了解新特性。</li></ul></li></ul><hr><h3 id="📦-perf-tools-brendan-gregg-的脚本百宝箱" tabindex="-1">📦 perf-tools：Brendan Gregg 的脚本百宝箱 <a class="header-anchor" href="#📦-perf-tools-brendan-gregg-的脚本百宝箱" aria-label="Permalink to &quot;📦 perf-tools：Brendan Gregg 的脚本百宝箱&quot;">​</a></h3><p>不要被名字迷惑，<code>perf-tools</code> 实际上是大量基于 Ftrace 和 tracefs 的 Bash 脚本封装。在 eBPF 还没普及的年代，它们是主力军，现在依然因为「无需编译、直接运行」而极具价值。</p><ul><li><p><strong>GitHub Repository</strong></p><ul><li><a href="https://github.com/brendangregg/perf-tools/" target="_blank" rel="noreferrer">https://github.com/brendangregg/perf-tools/</a></li></ul></li><li><p><strong>Examples Directory</strong></p><ul><li><a href="https://github.com/brendangregg/perf-tools/tree/master/examples" target="_blank" rel="noreferrer">https://github.com/brendangregg/perf-tools/tree/master/examples</a></li><li><strong>建议</strong>：直接去读这些脚本的源码——它们就是最好的 Ftrace 使用教程。你可以看到作者是如何组装简单的 <code>echo</code> 命令来实现复杂功能的。</li></ul></li><li><p><strong>Linux Performance Analysis: New Tools and Old Secrets</strong></p><ul><li><em>Brendan Gregg, USENIX LISA14, Nov 2014</em></li><li><a href="https://www.usenix.org/conference/lisa14/conference-program/presentation/gregg" target="_blank" rel="noreferrer">Video</a> | <a href="https://www.slideshare.net/brendangregg/linux-performance-analysis-new-tools-and-old-secrets" target="_blank" rel="noreferrer">Slides</a></li><li><strong>地位</strong>：经典演讲。如果你想系统性地学习 Linux 性能分析的方法论，而不是单纯学工具，看这个视频的时间花得最值。</li></ul></li></ul><hr><h3 id="🚀-ebpf-的延伸" tabindex="-1">🚀 eBPF 的延伸 <a class="header-anchor" href="#🚀-ebpf-的延伸" aria-label="Permalink to &quot;🚀 eBPF 的延伸&quot;">​</a></h3><p>我们在第 4 章讨论过 Kprobes 和 Instrumentation。eBPF 已经彻底改变了内核跟踪的格局。 虽然本章重点在 Ftrace，但你必须知道它们的关系：Ftrace 是底层的基石，eBPF 是在上层构建的高级大厦。</p><ul><li><strong>eBPF and frontends resources</strong><ul><li>参见 <strong>Chapter 4 (Debug via Instrumentation – Kprobes)</strong> 的 &quot;Further reading&quot; 部分。</li></ul></li></ul><hr><h3 id="📡-lttng-高频数据的工业级方案" tabindex="-1">📡 LTTng：高频数据的工业级方案 <a class="header-anchor" href="#📡-lttng-高频数据的工业级方案" aria-label="Permalink to &quot;📡 LTTng：高频数据的工业级方案&quot;">​</a></h3><p>当 Ftrace 的开销在高频事件下成为瓶颈，或者你需要分析用户空间和内核空间的关联时，LTTng 是最佳选择。</p><ul><li><p><strong>LTTng Main Website &amp; Quick start</strong></p><ul><li><a href="https://lttng.org/" target="_blank" rel="noreferrer">https://lttng.org/</a></li><li><a href="https://lttng.org/docs/v2.13/#doc-getting-started" target="_blank" rel="noreferrer">Documentation v2.13+</a></li></ul></li><li><p><strong>Babeltrace 2 (CLI Tool)</strong></p><ul><li><a href="https://lttng.org/blog/2020/06/01/bt2-cli/" target="_blank" rel="noreferrer">https://lttng.org/blog/2020/06/01/bt2-cli/</a></li><li><strong>说明</strong>：LTTng 生成的 CTF (Common Trace Format) 数据是二进制的，<code>babeltrace2</code> 是用来把它转成人能读的文本的工具。</li></ul></li><li><p><strong>Finding the Root Cause of a Web Request Latency</strong></p><ul><li><em>Julien Desfossez, Feb 2015</em></li><li><a href="https://lttng.org/blog/2015/02/04/web-request-latency-root-cause/" target="_blank" rel="noreferrer">https://lttng.org/blog/2015/02/04/web-request-latency-root-cause/</a></li><li><strong>案例价值</strong>：展示了如何结合内核和用户空间跟踪来定位一个真实的业务问题。</li></ul></li><li><p><strong>Tutorial: Remotely tracing an embedded Linux system</strong></p><ul><li><em>C Babeux, Mar 2016</em></li><li><a href="https://lttng.org/blog/2016/03/07/tutorial-remote-tracing/" target="_blank" rel="noreferrer">https://lttng.org/blog/2016/03/07/tutorial-remote-tracing/</a></li><li><strong>适用场景</strong>：正如我们在本章结尾提到的，嵌入式板子资源有限。这篇教程教你在板子上采集，在主机上分析的正确姿势。</li></ul></li><li><p><strong>LTTng: A Comprehensive User&#39;s Guide (version 2.3)</strong></p><ul><li><em>Daniel U. Thibault (DRDC Valcartier Research Centre)</em></li><li><a href="https://cradpdf.drdc-rddc.gc.ca/PDFS/unc246/p804561_A1b.pdf" target="_blank" rel="noreferrer">PDF</a></li><li><strong>说明</strong>：这是一本小书。如果你需要一本纸质书（或 PDF）放在案头从头读到尾，选这个。</li></ul></li></ul><p><strong>Trace Compass (LTTng 的可视化前端)</strong></p><ul><li><strong>Trace Compass Website</strong><ul><li><a href="https://www.eclipse.org/tracecompass/#home" target="_blank" rel="noreferrer">https://www.eclipse.org/tracecompass/#home</a></li></ul></li><li><strong>Alternate tracing tools</strong><ul><li><a href="https://lttng.org/docs/v2.13/#doc-lttng-alternatives" target="_blank" rel="noreferrer">https://lttng.org/docs/v2.13/#doc-lttng-alternatives</a></li><li><strong>比较</strong>：这里列出了 LTTng 与其他工具（如 SystemTap, perf）的对比，帮你决定在什么时候用 LTTng。</li></ul></li></ul><hr><h3 id="🔧-杂项-特殊场景与技巧" tabindex="-1">🔧 杂项：特殊场景与技巧 <a class="header-anchor" href="#🔧-杂项-特殊场景与技巧" aria-label="Permalink to &quot;🔧 杂项：特殊场景与技巧&quot;">​</a></h3><p>最后，这里有几个在特定场景下能救命的资源：</p><ul><li><p><strong>Boot-time tracing via ftrace</strong></p><ul><li><a href="https://www.kernel.org/doc/html/latest/trace/boottime-trace.html" target="_blank" rel="noreferrer">Documentation</a></li><li><strong>痛点解决</strong>：如何跟踪内核启动早期的过程？那时候 <code>/sys</code> 还没挂载呢。这篇文章教你通过内核参数 (<code>ftrace=</code>) 来解决这个问题。</li></ul></li><li><p><strong>Trace Linux System Calls with Least Impact on Performance</strong></p><ul><li><em>PingCAP, Dec 2020</em></li><li><a href="https://en.engpic.com/blog/how-to-trace-linux-system-calls-in-production-with-minimal-impact-on-performance/" target="_blank" rel="noreferrer">https://en.engpic.com/blog/how-to-trace-linux-system-calls-in-production-with-minimal-impact-on-performance/</a></li><li><strong>场景</strong>：在生产环境（Production）进行系统调用跟踪。这里讨论了如何在不拖垮业务的前提下获取数据。</li></ul></li></ul><hr><p>把所有这些工具都装进你的工具箱里。在不同的场景下，针对不同的问题，选择最锋利的那把刀。</p><p>下一章，我们要面对一个更沉重的话题：<strong>Kernel Panic</strong>。别慌，有了今天的调试利器，哪怕是内核崩溃，我们也能从尸体里读出点东西来。</p><hr><h2 id="练习题" tabindex="-1">练习题 <a class="header-anchor" href="#练习题" aria-label="Permalink to &quot;练习题&quot;">​</a></h2><h3 id="练习-1-understanding" tabindex="-1">练习 1：understanding <a class="header-anchor" href="#练习-1-understanding" aria-label="Permalink to &quot;练习 1：understanding&quot;">​</a></h3><p><strong>题目</strong>：比较 Tracing（跟踪）和 Profiling（性能分析）的主要区别。如果内核开发者想要获取某个系统调用在内核内部完整的函数调用流程，应该使用哪种技术？为什么？</p><details><summary>答案与解析</summary><p><strong>答案</strong>：应使用 Tracing。</p><p>区别：</p><ol><li>Tracing 是捕获性的，记录代码执行路径上的所有细节（函数调用、参数、时间戳等），提供完整的执行历史。</li><li>Profiling 是统计性的，通过周期性采样来捕获事件，不捕获所有细节，主要用于发现性能热点。</li></ol><p>原因：获取“完整的函数调用流程”需要记录代码执行的每一个步骤，而不是统计样本，因此必须使用 Tracing。</p><p><strong>解析</strong>：这道题考察对核心概念的定义辨析。根据章节开头定义，Tracing 类似于“黑匣子”，记录所有细节；而 Profiling 旨在通过采样进行性能监控。Strace 是系统调用边界的 Tracing，而 Ftrace 则深入内核进行 Tracing。要查看内部流程，必须使用具有完整记录能力的 Tracing 技术。</p></details><h3 id="练习-2-understanding" tabindex="-1">练习 2：understanding <a class="header-anchor" href="#练习-2-understanding" aria-label="Permalink to &quot;练习 2：understanding&quot;">​</a></h3><p><strong>题目</strong>：在 Linux 内核配置中，<code>CONFIG_DYNAMIC_FTRACE</code> 选项的作用是什么？如果没有开启这个选项，直接使用 <code>-pg</code> 编译器选项进行插桩，会对生产环境的内核性能产生什么影响？</p><details><summary>答案与解析</summary><p><strong>答案</strong>：作用：允许内核在运行时动态修改机器指令（将函数入口处的指令替换为 NOP 指令或跳转到 Trampoline），从而在不跟踪时实现零性能损耗。</p><p>影响：如果没有开启此选项，内核将保留编译器插入的 <code>mcount</code> 调用。每个函数调用的入口都会执行判断逻辑（类似 <code>if tracing_enabled { ... }</code>），这会带来巨大的 CPU 开销，不适合在生产环境开启。</p><p><strong>解析</strong>：考察对 Ftrace 实现机制的理解。普通的编译器插桩（<code>-pg</code>）会永久性地在每个函数入口添加代码，导致性能下降。而动态 Ftrace 利用了内核的自我修改代码能力，在未开启跟踪时通过填空指令来维持原生性能。</p></details><h3 id="练习-3-application" tabindex="-1">练习 3：application <a class="header-anchor" href="#练习-3-application" aria-label="Permalink to &quot;练习 3：application&quot;">​</a></h3><p><strong>题目</strong>：假设你正在调试一个随机的内核崩溃，并且怀疑崩溃发生在一系列复杂的内核函数调用之后。你希望在崩溃发生时自动捕获 Ftrace 缓冲区中的数据，以便分析崩溃前的执行流。请给出具体的操作步骤或配置方法。</p><details><summary>答案与解析</summary><p><strong>答案</strong>：可以通过以下方法之一实现：</p><ol><li><p><strong>内核参数启动配置</strong>：在内核启动参数中加入 <code>ftrace_dump_on_oops</code>。 例如：<code>ftrace_dump_on_oops=1</code>（在 Oops 时向控制台转储）或 <code>ftrace_dump_on_oops=2</code>（转储更多原始缓冲区内容）。</p></li><li><p><strong>运行时配置（Procfs）</strong>：在系统运行时，通过 Proc 文件系统接口开启： <code>echo 1 &gt; /proc/sys/kernel/ftrace_dump_on_oops</code></p></li></ol><p>这样，一旦内核发生 Panic 或 Oops，Ftrace 会自动将 Ring Buffer 中的跟踪日志转储到控制台和日志中，供事后分析。</p><p><strong>解析</strong>：考察实际调试场景的应用能力。知识点来自 <code>ftrace_dump_on_oops</code>。这是处理“事后分析”类问题的关键技巧，因为一旦内核崩溃，通常无法手动执行命令复制 trace 文件，必须依赖内核的自动转储机制。</p></details><h3 id="练习-4-application" tabindex="-1">练习 4：application <a class="header-anchor" href="#练习-4-application" aria-label="Permalink to &quot;练习 4：application&quot;">​</a></h3><p><strong>题目</strong>：你正在使用 <code>function_graph</code> 跟踪器分析一个延迟敏感的内核模块。为了过滤掉噪音，你只想跟踪与该模块相关的函数，并且只想观察执行时间超过 100 微秒的函数调用。请结合 <code>set_ftrace_filter</code> 和 Ftrace 的延迟标记特性，描述如何配置。</p><details><summary>答案与解析</summary><p><strong>答案</strong>：配置步骤如下：</p><ol><li><p><strong>设置过滤器</strong>：将模块相关的函数名写入 <code>set_ftrace_filter</code>。 <code>echo &#39;mod:*&#39; &gt; /sys/kernel/tracing/set_ftrace_filter</code> (注：<code>mod:</code> 是一个过滤命令，用于匹配特定模块的所有函数，假设已知模块名，也可以直接使用通配符如 <code>my_module_*</code>)</p></li><li><p><strong>启用延迟标记</strong>：虽然 <code>function_graph</code> 本身会显示 Duration（持续时间），但 Ftrace 提供了延迟标记功能来直观地突显异常。 确保 <code>options/funcgraph-cpu</code> 和 <code>options/funcgraph-duration</code> 已开启（默认通常开启）。 在 Trace 输出中，持续时间列左侧出现的符号（如 <code>!</code>）表示函数执行时间超过了特定的阈值（例如 <code>!</code> 通常代表超过 100us 或更高阈值，具体取决于内核配置）。</p></li><li><p><strong>读取分析</strong>： <code>cat /sys/kernel/tracing/trace</code> | grep &#39;!&#39;</p></li></ol><p>或者，如果使用 <code>perf-tools</code>，可以直接使用 <code>funcslower</code> 脚本： <code>./funcslower 100</code> (这会直接显示超过 100us 的函数)。</p><p><strong>解析</strong>：考察对 Ftrace 过滤功能和输出解读的综合应用。题目要求结合 <code>set_ftrace_filter</code>（缩小跟踪范围）和对延迟标记的理解（识别长耗时函数）。实际操作中，利用 <code>mod:</code> 过滤命令或通配符是常见的排查手段，而观察 Duration 列的符号（如 $, +, !）是快速定位性能瓶颈的关键。</p></details><h3 id="练习-5-thinking" tabindex="-1">练习 5：thinking <a class="header-anchor" href="#练习-5-thinking" aria-label="Permalink to &quot;练习 5：thinking&quot;">​</a></h3><p><strong>题目</strong>：在阅读 Ftrace 的 <code>function_graph</code> 输出时，你注意到某个特定的内核线程（PID 123）在日志中显示了函数调用的缩进和持续时间，但根据你的理解，该线程当时应该完全处于休眠状态。请分析可能产生这种“幽灵”跟踪数据的原因，并说明如何利用 Ftrace 的 <code>latency-format</code> 选项来验证你的推测。</p><details><summary>答案与解析</summary><p><strong>答案</strong>：<strong>可能原因分析</strong>： 这种现象最可能的原因是<strong>中断上下文的干扰</strong>。虽然日志显示的是“PID 123 线程”上下文，但实际上记录的是硬件中断（Hard IRQ）或软中断在该线程被调度出去、或者是刚刚准备运行时切入到内核模式执行的处理函数。在 <code>function_graph</code> 默认输出下，中断处理函数的执行往往归入当前被中断进程的上下文中，容易造成误解。</p><p><strong>验证方法</strong>：</p><ol><li>启用 <code>latency-format</code> 选项： <code>echo 1 &gt; /sys/kernel/tracing/options/latency-format</code></li><li>再次查看 Trace 输出。该格式会增加一列详细信息，显示中断状态、抢占计数器和上下文标志。</li><li><strong>分析标志</strong>：查看新增列中的标志位（如 <code>dN</code> 表示中断深度，<code>X</code> 表示存在 NMI 等）。如果看到中断标志位被置起，或者 <code>irqs-off</code> 相关的标记，就证明这些函数实际上是在中断上下文中执行的，而非 PID 123 线程主动发起的调用。</li></ol><p>这揭示了 <code>function_graph</code> 默认视图的一个局限性：它倾向于将底层活动的“账”算在当前运行的任务头上。</p><p><strong>解析</strong>：这是一道深度思考题，考察对内核执行上下文（进程上下文 vs 中断上下文）以及 Tracing 工具本身局限性的理解。单纯看 PID 可能会被误导，理解 <code>latency-format</code> 提供的底层硬件状态（如中断是否关闭、抢占是否禁用）是区分“进程主动行为”和“中断被动行为”的关键。</p></details><hr><h2 id="要点提炼" tabindex="-1">要点提炼 <a class="header-anchor" href="#要点提炼" aria-label="Permalink to &quot;要点提炼&quot;">​</a></h2><p>本章的核心在于如何利用 Linux 内核的跟踪技术揭开系统运行的“黑盒”。<strong>Ftrace</strong> 作为内核自带的跟踪引擎，通过 <strong>tracefs</strong> 文件系统提供了控制接口，利用编译器插桩技术（如将函数入口替换为 NOP 指令）实现了在不开启跟踪时对性能零损耗。理解 <strong>Tracing（跟踪）</strong> 与 <strong>Profiling（剖析）</strong> 的区别是选对工具的前提：前者关注连续的流程细节，记录每一次函数调用以回答“在某一时刻具体发生了什么”；后者关注统计热点，通过采样回答“时间都去哪儿了”。</p><p>要实现有效的内核观测，仅仅开启跟踪器是不够的，必须掌握上下文识别与高级过滤技巧。通过开启 <code>latency-format</code> 和 <code>funcgraph-proc</code> 等选项，用户可以解码出 <code>d.h2</code> 这种内核状态密码，从而区分代码是运行在进程上下文还是硬中断上下文，以及是否持有锁。同时，利用 <code>set_ftrace_filter</code> 配合 Glob 匹配或基于索引的过滤，能够将海量的函数调用日志精简到特定范围（如仅限 TCP 协议栈或特定驱动模块），这是在信息洪流中定位问题的关键。</p><p>在实际调试中，通过跟踪 <strong>Tracepoints（跟踪点）</strong> 比单纯跟踪函数调用能获取更多有价值的信息。Tracepoints 是内核开发者预先埋好的“钩子”，位于调度器、中断等关键路径上。使用 <code>set_event</code> 接口监听这些事件（如 <code>net:*</code> 或 <code>skb:*</code>），虽然可能牺牲了函数调用的层级缩进图，但能获取具体的<strong>函数参数值</strong>，这对于排查“参数错误导致丢包”等问题至关重要。</p><p>针对动态插入调试信息的需求，内核提供了 <strong><code>trace_printk()</code></strong> 这一轻量级 API，它优于传统的 <code>printk</code>。<code>trace_printk</code> 仅写入内存环形缓冲区，避免了控制台 I/O 带来的性能损耗和时序干扰，且不会因缓冲区溢出而丢失关键数据。结合 <code>trace_pipe</code> 实时流式输出，开发者可以在不中断系统运行的情况下，像观看直播一样监控内核行为，真正实现了对内核“显微镜”般的动态观测。</p>',70)])])}const u=r(l,[["render",a]]);export{h as __pageData,u as default};
